(() => {
  const ev = $json.data;
  const cfg = $('definir_agenda').first().json;
  const intervalo = cfg.timeBetweenMeetingsMinutes;
  const dayMap = {0:'DOM',1:'SEG',2:'TER',3:'QUA',4:'QUI',5:'SEX',6:'SAB'};
  const pad = n => String(n).padStart(2,'0');

  // FIX TIMEZONE: Forçar todas as operações em America/Sao_Paulo
  // Usar offset -03:00 para criar datas consistentes
  function spNow() {
    // Gerar "agora" em SP: pegar UTC e subtrair 3h para ter horário SP
    const utc = new Date();
    return new Date(utc.getTime() - 3 * 60 * 60 * 1000);
  }

  function toSPDate(dateStr) {
    // Converter qualquer dateTime ISO para timestamp absoluto
    // Se já tem offset (-03:00), Date() interpreta corretamente
    // Se não tem offset, assumir que é São Paulo e adicionar -03:00
    if (dateStr && !dateStr.match(/[+-]\d{2}:\d{2}$/) && !dateStr.endsWith('Z')) {
      dateStr = dateStr + '-03:00';
    }
    return new Date(dateStr);
  }

  function getSlot(date, t) {
    const [h,m] = t.split(':').map(Number);
    const d = new Date(date);
    d.setHours(h,m,0,0);
    return d;
  }

  function sameDay(a,b) {
    return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate();
  }

  const result = [];
  const hoje = spNow();
  hoje.setHours(0,0,0,0);

  // FIX: Converter eventos para timestamps absolutos via toSPDate
  const eventos = Array.isArray(ev)
    ? ev.filter(e => e?.start?.dateTime && e?.end?.dateTime).map(e => ({
        start: toSPDate(e.start.dateTime),
        end: toSPDate(e.end.dateTime)
      }))
    : [];

  for(let i=0; i<12*7; i++){
    const d = new Date(hoje);
    d.setDate(hoje.getDate()+i);
    d.setHours(0,0,0,0);
    const dia = dayMap[d.getDay()];
    const c = cfg.schedule.find(s => s.day===dia);
    if(!c || !c.available) continue;
    const ini = getSlot(d, c.hours.after);
    const fim = getSlot(d, c.hours.before);

    // Filtrar eventos do mesmo dia (comparando em horário SP)
    const evDia = eventos.filter(e => sameDay(e.start, d) || sameDay(e.end, d));

    for(let s=new Date(ini); s<fim;) {
      const sf = new Date(s.getTime()+intervalo*60000);
      if(sf>fim) break;

      // FIX: Comparar slots (horário SP) com eventos (convertidos para SP)
      const conflito = evDia.some(e => s < e.end && sf > e.start);

      if(!conflito) {
        result.push({
          data: s.toISOString().split('T')[0],
          start: pad(s.getHours())+':'+pad(s.getMinutes()),
          end: pad(sf.getHours())+':'+pad(sf.getMinutes())
        });
      }
      s = sf;
    }
  }
  return JSON.stringify(result);
})()
}}

