const slots=items[0].json.data||[];
const agrup={};
for(const s of slots){if(!agrup[s.data])agrup[s.data]=[];agrup[s.data].push(s.start);}
const hoje=new Date();
// FIX: Usar data SP para filtrar hoje
const spNow=new Date(hoje.getTime()-3*60*60*1000);
const hojeStr=spNow.toISOString().split('T')[0];
const dias=Object.keys(agrup).filter(d=>d!==hojeStr).sort();
const sel=[];
const ph=h=>{const[hh,mm]=h.split(':').map(Number);return{hh,mm};};
for(const dia of dias.slice(0,10)){
  const ord=agrup[dia].sort();
  const man=ord.filter(h=>{const{hh}=ph(h);return hh<12;});
  const tar=ord.filter(h=>ph(h).hh>=13).slice(0,10);
  const [y,mo,d]=dia.split('-');
  [...man,...tar].forEach(h=>sel.push(`${d}/${mo} às ${h}`));
}
return [{json:{disponibilidade:sel.join(', ')}}];

